      { name: "Amoxicillin", type: "Penicillin Antibiotic", action: "Bactericidal against common ENT pathogens", sideEffects: "Diarrhea, rash, allergic reaction", contra: "Penicillin allergy", pearl: "First-line for acute otitis media and strep pharyngitis in non-allergic patients." }
